    33	/* This application links in drmemtrace_static and acquires a trace during
    34	 * a "burst" of execution in the middle of the application.  It then detaches.
    35	 */
    36	
    37	#include "test_helpers.h"
    38	/* We deliberately do not include configure.h here to simulate what an
    39	 * actual app will look like.  configure_DynamoRIO_static sets DR_APP_EXPORTS
    40	 * for us.
    41	 */
    42	#include "dr_api.h"
    43	#include <assert.h>
    44	#include <iostream>
    45	#include <math.h>
    46	#include <stdlib.h>
    47	
    48	namespace dynamorio {
    49	namespace drmemtrace {
    50	
    51	bool
    52	my_setenv(const char *var, const char *value)
    53	{
    54	#ifdef UNIX
    55	    return setenv(var, value, 1 /*override*/) == 0;
    56	#else
    57	    return SetEnvironmentVariable(var, value) == TRUE;
    58	#endif
    59	}
    60	
    61	static int
    62	do_some_work(int arg)
    63	{
    64	    static int iters = 512;
    65	    double val = (double)arg;
    66	    for (int i = 0; i < iters; ++i) {
    67	        val += sin(val);
    68	    }
    69	    return (val > 0);
    70	}
    71	
    72	int
    73	test_main(int argc, const char *argv[])
    74	{
    75	    static int outer_iters = 2048;
    76	    /* We trace a 4-iter burst of execution. */
    77	    static int iter_start = outer_iters / 3;
    78	    static int iter_stop = iter_start + 4;
    79	
    80	    /* We also test -rstats_to_stderr */
    81	    if (!my_setenv("DYNAMORIO_OPTIONS",
    82	                   "-stderr_mask 0xc -rstats_to_stderr "
    83	                   "-client_lib ';;-offline'"))
    84	        std::cerr << "failed to set env var!\n";
    85	
    86	    /* We use an outer loop to test re-attaching (i#2157). */
    87	    for (int j = 0; j < 3; ++j) {
    88	        std::cerr << "pre-DR init\n";
    89	        dr_app_setup();
    90	        assert(!dr_app_running_under_dynamorio());
    91	
    92	        for (int i = 0; i < outer_iters; ++i) {
    93	            if (i == iter_start) {
    94	                std::cerr << "pre-DR start\n";
    95	                dr_app_start();
    96	            }
    97	            if (i >= iter_start && i <= iter_stop)
    98	                assert(dr_app_running_under_dynamorio());
    99	            else
   100	                assert(!dr_app_running_under_dynamorio());
   101	            if (do_some_work(i) < 0)
   102	                std::cerr << "error in computation\n";
   103	            if (i == iter_stop) {
   104	                std::cerr << "pre-DR detach\n";
   105	                dr_app_stop_and_cleanup();
   106	            }
   107	        }
   108	        std::cerr << "all done\n";
   109	    }
   110	    return 0;
   111	}
   112	
   113	/* FIXME i#2099: the weak symbol is not supported on Windows. */
   114	#if defined(UNIX) && defined(TEST_APP_DR_CLIENT_MAIN)
   115	#    ifdef __cplusplus
   116	extern "C" {
   117	#    endif
