   120	DR_EXPORT WEAK void
   121	drmemtrace_client_main(client_id_t id, int argc, const char *argv[])
   122	{
   123	    std::cerr << "wrong drmemtrace_client_main\n";
   124	}
   125	
   126	/* This dr_client_main should be called instead of the one in tracer.cpp */
   127	DR_EXPORT void
   128	dr_client_main(client_id_t id, int argc, const char *argv[])
   129	{
   130	    std::cerr << "app dr_client_main\n";
   131	    drmemtrace_client_main(id, argc, argv);
   132	}
