  message(STATUS "drmemtrace_static target missing")
else ()
  message(STATUS "drmemtrace_static target exists")
endif ()
add_executable(burst_separate main.cpp)
configure_DynamoRIO_static(burst_separate)
use_DynamoRIO_static_client(burst_separate drmemtrace_static)
CMAKE
cat > "$work/src/main.cpp" <<'CPP'
