    dr_app_setup();
    dr_app_stop_and_cleanup();
    return 0;
}
CPP
cmake -S "$work/src" -B "$work/build" -G Ninja \
  -DCMAKE_BUILD_TYPE=Debug -DDEBUG=ON -DDynamoRIO_DIR:PATH="$build/cmake"
